import os
from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_jwt_identity
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', 'your-secret-key')
jwt = JWTManager(app)

# In-memory storage
users = {}
user_id_counter = 1

def get_user_id(username):
    if username not in users:
        return None
    return list(users.keys()).index(username) + 1

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    if 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Missing username or password'}), 400
    if data['username'] in users:
        return jsonify({'error': 'Username already exists'}), 400
    hashed_password = generate_password_hash(data['password'])
    users[data['username']] = hashed_password
    user_id = user_id_counter
    user_id_counter += 1
    return jsonify({'message': 'User registered', 'id': user_id}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    if 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Missing username or password'}), 400
    if data['username'] not in users:
        return jsonify({'error': 'Invalid credentials'}), 401
    if not check_password_hash(users[data['username']], data['password']):
        return jsonify({'error': 'Invalid credentials'}), 401
    access_token = create_access_token(identity=data['username'])
    return jsonify({'token': access_token}), 200

@app.route('/profile', methods=['GET'])
@jwt_required()
def profile():
    current_user = get_jwt_identity()
    user_id = get_user_id(current_user)
    if user_id is None:
        return jsonify({'error': 'Invalid token'}), 401
    return jsonify({'id': user_id, 'username': current_user}), 200

if __name__ == '__main__':
    app.run(debug=True)
